class EncryptionHelper:
    """Helper class for encrypting/decrypting sensitive data before storing in Redis."""

    def __init__(self, encryption_key: str):
        if not encryption_key or len(encryption_key) < 32:
            raise ValueError("Encryption key must be at least 32 characters long")
        self._key = encryption_key.encode('utf-8')[:32]

    def _derive_key(self, salt: bytes) -> bytes:
        """Derive a key using HMAC-SHA256."""
        return hmac.new(self._key, salt, hashlib.sha256).digest()

    def encrypt(self, plaintext: str) -> str:
        """Encrypt data using XOR with HMAC-derived key stream (lightweight encryption).
        For production, use a proper encryption library like cryptography (Fernet)."""
        salt = secrets.token_bytes(16)
        derived_key = self._derive_key(salt)
        plaintext_bytes = plaintext.encode('utf-8')

        # Generate keystream using HMAC in counter mode
        keystream = b''
        counter = 0
        while len(keystream) < len(plaintext_bytes):
            block = hmac.new(
                derived_key,
                counter.to_bytes(4, 'big'),
                hashlib.sha256
            ).digest()
            keystream += block
            counter += 1

        encrypted = bytes(a ^ b for a, b in zip(plaintext_bytes, keystream[:len(plaintext_bytes)]))

        # Compute HMAC for integrity
        mac = hmac.new(derived_key, encrypted, hashlib.sha256).digest()

        # Combine: salt + mac + encrypted
        combined = salt + mac + encrypted
        return combined.hex()

    def decrypt(self, ciphertext_hex: str) -> str:
        """Decrypt data."""
        combined = bytes.fromhex(ciphertext_hex)
        salt = combined[:16]
        mac = combined[16:48]
        encrypted = combined[48:]

        derived_key = self._derive_key(salt)

        # Verify HMAC
        expected_mac = hmac.new(derived_key, encrypted, hashlib.sha256).digest()
        if not hmac.compare_digest(mac, expected_mac):
            raise ValueError("Data integrity check failed - possible tampering detected")

        # Generate keystream
        keystream = b''
        counter = 0
        while len(keystream) < len(encrypted):
            block = hmac.new(
                derived_key,
                counter.to_bytes(4, 'big'),
                hashlib.sha256
            ).digest()
            keystream += block
            counter += 1

        decrypted = bytes(a ^ b for a, b in zip(encrypted, keystream[:len(encrypted)]))
        return decrypted.decode('utf-8')


def retry_on_failure(max_retries: int = 3, delay: float = 0.5):
    """Decorator for retrying Redis operations on transient failures."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(max_retries):
                try:
                    return func(*args, **kwargs)
                except (ConnectionError, TimeoutError) as e:
                    last_exception = e
                    wait_time = delay * (2 ** attempt)
                    logger.warning(
                        f"Redis operation failed (attempt {attempt + 1}/{max_retries}): {e}. "
                        f"Retrying in {wait_time}s..."
                    )
                    time.sleep(wait_time)
                except RedisError as e:
                    logger.error(f"Non-retryable Redis error: {e}")
                    raise
            logger.error(f"All {max_retries} retry attempts failed")
            raise last_exception
        return wrapper
    return decorator


class SecureRedisConfig:
    """Configuration for secure Redis connection."""

    def __init__(self):
        self.redis_nodes = self._parse_nodes(
            os.environ.get('REDIS_CLUSTER_NODES', 'localhost:6379')
        )
        self.redis_password = os.environ.get('REDIS_PASSWORD')
        self.redis_username = os.environ.get('REDIS_USERNAME', 'default')
        self.encryption_key = os.environ.get('REDIS_ENCRYPTION_KEY')

        # TLS Configuration
        self.tls_enabled = os.environ.get('REDIS_TLS_ENABLED', 'true').lower() == 'true'
        self.tls_cert_file = os.environ.get('REDIS_TLS_CERT_FILE')
        self.tls_key_file = os.environ.get('REDIS_TLS_KEY_FILE')
        self.tls_ca_cert_file = os.environ.get('REDIS_TLS_CA_CERT_FILE')
        self.tls_cert_reqs = os.environ.get('REDIS_TLS_CERT_REQS', 'required')

        # Connection settings
        self.socket_timeout = float(os.environ.get('REDIS_SOCKET_TIMEOUT', '5'))
        self.socket_connect_timeout = float(os.environ.get('REDIS_CONNECT_TIMEOUT', '5'))
        self.max_connections = int(os.environ.get('REDIS_MAX_CONNECTIONS', '50'))
        self.health_check_interval = int(os.environ.get('REDIS_HEALTH_CHECK_INTERVAL', '30'))

        # Cluster mode
        self.cluster_mode = os.environ.get('REDIS_CLUSTER_MODE', 'true').lower() == 'true'

        self._validate()

    def _parse_nodes(self, nodes_str: str) -> list:
        """Parse comma-separated host:port pairs."""
        nodes = []
        for node in nodes_str.split(','):
            node = node.strip()
            if ':' in node:
                host, port = node.rsplit(':', 1)
                nodes.append(ClusterNode(host, int(port)))
            else:
                nodes.append(ClusterNode(node, 6379))
        return nodes

    def _validate(self):
        """Validate configuration."""
        if not self.redis_password:
            raise ValueError(
                "REDIS_PASSWORD environment variable is required. "
                "Redis must be configured with authentication."
            )

        if not self.encryption_key:
            raise ValueError(
                "REDIS_ENCRYPTION_KEY environment variable is required "
                "for encrypting sensitive data at rest."
            )

        if not self.tls_enabled:
            raise ValueError(
                "TLS must be enabled for secure Redis connections. "
                "Set REDIS_TLS_ENABLED=true and provide TLS certificates. "
                "Unencrypted connections are not permitted for sensitive data."
            )

    def create_ssl_context(self) -> ssl.SSLContext:
        """Create a properly configured SSL context for Redis TLS connection."""
        ssl_context = ssl.SSLContext(ssl.PROTOCOL_TLS_CLIENT)

        # Set minimum TLS version to 1.2
        ssl_context.minimum_version = ssl.TLSVersion.TLSv1_2

        # Disable older insecure protocols explicitly
        ssl_context.options |= ssl.OP_NO_SSLv2
        ssl_context.options |= ssl.OP_NO_SSLv3
        ssl_context.options |= ssl.OP_NO_TLSv1
        ssl_context.options |= ssl.OP_NO_TLSv1_1

        # Certificate verification
        if self.tls_cert_reqs == 'required':
            ssl_context.check_hostname = True
            ssl_context.verify_mode = ssl.CERT_REQUIRED
        elif self.tls_cert_reqs == 'optional':
            ssl_context.check_hostname = False
            ssl_context.verify_mode = ssl.CERT_OPTIONAL
        else:
            # Even 'none' should not be used in production
            raise ValueError(
                "Certificate verification must be 'required' or 'optional'. "
                "Disabling certificate verification is not permitted."
            )

        # Load CA certificate for server verification
        if self.tls_ca_cert_file:
            ssl_context.load_verify_locations(self.tls_ca_cert_file)
        else:
            # Use system default CA certificates
            ssl_context.load_default_certs()

        # Load client certificate and key for mutual TLS (mTLS)
        if self.tls_cert_file and self.tls_key_file:
            ssl_context.load_cert_chain(
                certfile=self.tls_cert_file,
                keyfile=self.tls_key_file
            )
            logger.info("Mutual TLS (mTLS) configured with client certificate")

        logger.info(
            f"SSL context created: min_version=TLSv1.2, "
            f"verify_mode={ssl_context.verify_mode}, "
            f"check_hostname={ssl_context.check_hostname}"
        )

        return ssl_context


class SecureRedisCacheService:
    """Microservice for distributed caching with secure Redis cluster connection."""

    def __init__(self, config: Optional[SecureRedisConfig] = None):
        self._config = config or SecureRedisConfig()
        self._encryption = EncryptionHelper(self._config.encryption_key)
