    def _create_connection(self) -> redis.RedisCluster | redis.Redis:
        """Create a secure Redis connection with TLS."""
        ssl_context = self._config.create_ssl_context()

        common_kwargs = {
            'password': self._config.redis_password,
            'username': self._config.redis_username,
            'ssl': True,
            'ssl_context': ssl_context,
            'socket_timeout': self._config.socket_timeout,
            'socket_connect_timeout': self._config.socket_connect_timeout,
            'health_check_interval': self._config.health_check_interval,
            'decode_responses': True,
            'retry_on_timeout': True,
        }

        if self._config.cluster_mode:
            client = RedisCluster(
                startup_nodes=self._config.redis_nodes,
                max_connections=self._config.max_connections,
                skip_full_coverage_check=False,
                **common_kwargs
            )
            logger.info(
                f"Connected to Redis cluster with {len(self._config.redis_nodes)} "
                f"startup nodes via TLS"
            )
        else:
            node = self._config.redis_nodes[0]
            client = redis.Redis(
                host=node.host,
                port=node.port,
                max_connections=self._config.max_connections,
                **common_kwargs
            )
            logger.info(f"Connected to Redis at {node.host}:{node.port} via TLS")

        # Verify connection
        client.ping()
        logger.info("Redis connection verified with PING")

        return client

    def _build_key(self, prefix: str, identifier: str) -> str:
        """Build a namespaced Redis key."""
        # Hash the identifier to prevent key injection attacks
        safe_id = hashlib.sha256(identifier.encode('utf-8')).hexdigest()[:16]
        return f"{prefix}{safe_id}"

