    # --- Rate Limiting ---

    @retry_on_failure(max_retries=2)
    def check_rate_limit(
        self,
        identifier: str,
        max_requests: int = 100,
        window_seconds: int = RATE_LIMIT_TTL
    ) -> Dict[str, Any]:
        """Check and enforce rate limiting using sliding window."""
        key = self._build_key(KEY_PREFIX_RATE_LIMIT, identifier)

        pipe = self._client.pipeline()
        pipe.incr(key)
        pipe.ttl(key)
        results = pipe.execute()

        current_count = results[0]
        current_ttl = results[1]

        # Set TTL on first request
        if current_ttl == -1:
            self._client.expire(key, window_seconds)
            current_ttl = window_seconds

        allowed = current_count <= max_requests

        result = {
            'allowed': allowed,
            'current_count': current_count,
            'max_requests': max_requests,
            'remaining': max(0, max_requests - current_count),
            'reset_in_seconds': current_ttl if current_ttl > 0 else window_seconds,
        }

        if not allowed:
            logger.warning(f"Rate limit exceeded for {identifier[:8]}***: {current_count}/{max_requests}")

        return result

