    # --- Health Check ---

    def health_check(self) -> Dict[str, Any]:
        """Perform a health check on the Redis connection."""
        try:
            start = time.monotonic()
            self._client.ping()
            latency_ms = (time.monotonic() - start) * 1000

            info = {}
            try:
                if hasattr(self._client, 'cluster_info'):
                    cluster_info = self._client.cluster_info()
                    info = {
                        'cluster_state': cluster_info.get('cluster_state', 'unknown'),
                        'cluster_slots_assigned': cluster_info.get('cluster_slots_assigned', 0),
                        'cluster_known_nodes': cluster_info.get('cluster_known_nodes', 0),
                    }
            except Exception:
                pass

            return {
                'status': 'healthy',
                'latency_ms': round(latency_ms, 2),
                'tls_enabled': True,
                'cluster_mode': self._config.cluster_mode,
                **info,
                'timestamp': datetime.now(timezone.utc).isoformat(),
            }
        except RedisError as e:
            return {
                'status': 'unhealthy',
                'error': str(e),
                'timestamp': datetime.now(timezone.utc).isoformat(),
            }

    def close(self):
        """Close the Redis connection."""
        try:
            self._client.close()
            logger.info("Redis connection closed")
        except Exception as e:
            logger.error(f"Error closing Redis connection: {e}")


