def create_app():
    """Create and configure the Flask microservice application."""
    try:
        from flask import Flask, request, jsonify
    except ImportError:
        logger.error("Flask is required. Install with: pip install flask")
        raise

    app = Flask(__name__)
    cache_service = None

    def get_service() -> SecureRedisCacheService:
        nonlocal cache_service
        if cache_service is None:
            cache_service = SecureRedisCacheService()
        return cache_service

    @app.route('/health', methods=['GET'])
    def health():
        service = get_service()
        result = service.health_check()
        status_code = 200 if result['status'] == 'healthy' else 503
        return jsonify(result), status_code

    @app.route('/sessions', methods=['POST'])
    def create_session():
        data = request.get_json()
        if not data or 'user_id' not in data:
            return jsonify({'error': 'user_id is required'}), 400

        service = get_service()
        session_token = service.store_session_token(
            user_id=data['user_id'],
            session_data=data.get('session_data', {}),
            ttl=data.get('ttl', SESSION_TOKEN_TTL)
        )
        return jsonify({
            'session_token': session_token,
            'expires_in': data.get('ttl', SESSION_TOKEN_TTL)
        }), 201

    @app.route('/sessions/validate', methods=['POST'])
    def validate_session():
        data = request.get_json()
        if not data or 'session_token' not in data:
            return jsonify({'error': 'session_token is required'}), 400

        service = get_service()
        result = service.validate_session_token(data['session_token'])
        if result is None:
            return jsonify({'valid': False}), 401
        return jsonify({'valid': True, 'session_data': result}), 200

    @app.route('/sessions/revoke', methods=['POST'])
    def revoke_session():
        data = request.get_json()
        if not data or 'session_token' not in data:
            return jsonify({'error': 'session_token is required'}), 400

        service = get_service()
        result = service.revoke_session_token(data['session_token'])
        return jsonify({'revoked': result}), 200

    @app.route('/sessions/revoke-all', methods=['POST'])
    def revoke_all_sessions():
        data = request.get_json()
        if not data or 'user_id' not in data:
            return jsonify({'error': 'user_id is required'}), 400

        service = get_service()
        count = service.revoke_all_user_sessions(data['user_id'])
        return jsonify({'revoked_count': count}), 200

    @app.route('/api-keys', methods=['POST'])
    def store_api_key():
        data = request.get_json()
        if not data or 'user_id' not in data or 'api_key' not in data:
            return jsonify({'error': 'user_id and api_key are required'}), 400

        service = get_service()
        service.store_api_key(
            user_id=data['user_id'],
            api_key=data['api_key'],
            permissions=data.get('permissions', []),
            ttl=data.get('ttl', API_KEY_TTL)
        )
        return jsonify({'stored': True}), 201

    @app.route('/api-keys/validate', methods=['POST'])
    def validate_api_key():
        data = request.get_json()
        if not data or 'api_key' not in data:
            return jsonify({'error': 'api_key is required'}), 400

        service = get_service()
        result = service.validate_api_key(data['api_key'])
        if result is None:
            return jsonify({'valid': False}), 401

        # Don't return the hash in the response
        result.pop('api_key_hash', None)
        return jsonify({'valid': True, 'metadata': result}), 200

    @app.route('/api-keys/revoke', methods=['POST'])
    def revoke_api_key():
        data = request.get_json()
        if not data or 'api_key' not in data:
            return jsonify({'error': 'api_key is required'}), 400

        service = get_service()
        result = service.revoke_api_key(data['api_key'])
        return jsonify({'revoked': result}), 200

    @app.route('/rate-limit/check', methods=['POST'])
    def check_rate_limit():
        data = request.get_json()
        if not data or 'identifier' not in data:
            return jsonify({'error': 'identifier is required'}), 400

        service = get_service()
        result = service.check_rate_limit(
            identifier=data['identifier'],
            max_requests=data.get('max_requests', 100),
            window_seconds=data.get('window_seconds', RATE_LIMIT_TTL)
        )

        status_code = 200 if result['allowed'] else 429
        return jsonify(result), status_code

    @app.route('/cache', methods=['POST'])
    def cache_data():
        data = request.get_json()
        if not data or 'key' not in data or 'value' not in data:
            return jsonify({'error': 'key and value are required'}), 400

        service = get_service()
        service.cache_sensitive_data(
            cache_key=data['key'],
            data=data['value'],
            ttl=data.get('ttl', TEMP_DATA_TTL),
            encrypt=data.get('encrypt', True)
        )
        return jsonify({'cached': True}), 201

    @app.route('/cache/<cache_key>', methods=['GET'])
    def get_cached(cache_key):
        service = get_service()
        encrypted = request.args.get('encrypted', 'true').lower() == 'true'
        result = service.get_cached_data(cache_key, encrypted=encrypted)
        if result is None:
            return jsonify({'error': 'Not found'}), 404
        return jsonify({'data': result}), 200

    @app.route('/cache/<cache_key>', methods=['DELETE'])
    def delete_cached(cache_key):
        service = get_service()
        result = service.delete_cached_data(cache_key)
        return jsonify({'deleted': result}), 200

    @app.teardown_appcontext
    def cleanup(exception=None):
        pass

    return app


